import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.ePeAWSvT.js";const c=JSON.parse('{"title":"Screen Policy: 성원머니 (거래내역 / 가상계좌 / 환불계좌 / 출금)","description":"","frontmatter":{},"headers":[],"relativePath":"성원머니_통합_Screen_Policy.md","filePath":"성원머니_통합_Screen_Policy.md"}'),h={name:"성원머니_통합_Screen_Policy.md"};function o(l,t,i,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="screen-policy-성원머니-거래내역-가상계좌-환불계좌-출금" tabindex="-1">Screen Policy: 성원머니 (거래내역 / 가상계좌 / 환불계좌 / 출금) <a class="header-anchor" href="#screen-policy-성원머니-거래내역-가상계좌-환불계좌-출금" aria-label="Permalink to &quot;Screen Policy: 성원머니 (거래내역 / 가상계좌 / 환불계좌 / 출금)&quot;">​</a></h1><hr><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>SCREEN_NAME</td><td>성원머니 &gt; 거래내역 / 가상계좌 변경 / 환불계좌 변경 / 출금 신청</td></tr><tr><td>화면 목적</td><td>성원머니 잔액 조회, 거래내역 확인, 가상계좌·환불계좌 관리 및 출금 신청 처리</td></tr><tr><td>화면 형태</td><td>마이페이지 단일 페이지 + 다이얼로그 (팝업)</td></tr></tbody></table><hr><h2 id="■-성원머니-메인-화면-구성" tabindex="-1">■ 성원머니 메인 화면 구성 <a class="header-anchor" href="#■-성원머니-메인-화면-구성" aria-label="Permalink to &quot;■ 성원머니 메인 화면 구성&quot;">​</a></h2><table tabindex="0"><thead><tr><th>영역</th><th>표시 항목</th></tr></thead><tbody><tr><td>잔액 표시</td><td>성원머니 잔액 (₩단위) + [출금] 버튼</td></tr><tr><td>환불계좌</td><td>등록된 환불계좌 은행명 + 계좌번호 + 예금주 표시</td></tr><tr><td>환불계좌 액션</td><td>[변경내역 발급 확인서] / [가상계좌 변경] 버튼</td></tr><tr><td>가상계좌</td><td>등록된 가상계좌 은행명 + 계좌번호 + 예금주 표시</td></tr><tr><td>가상계좌 액션</td><td>[환불계좌 변경] 버튼</td></tr></tbody></table><hr><h2 id="■-거래내역" tabindex="-1">■ 거래내역 <a class="header-anchor" href="#■-거래내역" aria-label="Permalink to &quot;■ 거래내역&quot;">​</a></h2><h3 id="필터-및-조회-조건" tabindex="-1">[필터 및 조회 조건] <a class="header-anchor" href="#필터-및-조회-조건" aria-label="Permalink to &quot;[필터 및 조회 조건]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>기간 필터</td><td>최근 1개월 / 최근 6개월 / 최근 1년 / 기간 설정 (직접 입력)</td></tr><tr><td>거래유형 필터</td><td>전체 (기본값) / 입금 / 사용 / 사용취소 / 출금 / 소멸 (복수 선택 가능)</td></tr><tr><td>페이지당 건수</td><td>20건씩 보기 (Dropdown 변경 가능)</td></tr></tbody></table><h3 id="거래내역-테이블-컬럼" tabindex="-1">[거래내역 테이블 컬럼] <a class="header-anchor" href="#거래내역-테이블-컬럼" aria-label="Permalink to &quot;[거래내역 테이블 컬럼]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>컬럼</th><th>내용</th></tr></thead><tbody><tr><td>거래일시</td><td>YYYY-MM-DD HH:MM 형식</td></tr><tr><td>거래유형</td><td>입금 / 사용 / 사용취소 / 출금 / 소멸</td></tr><tr><td>접수번호</td><td>사용·사용취소 건에 한해 표시 (예: sw823533)</td></tr><tr><td>내용</td><td>거래 유형별 내용 텍스트 표시</td></tr><tr><td>금액(₩)</td><td>+입금 / -차감 형태</td></tr><tr><td>잔액(₩)</td><td>해당 거래 후 잔액</td></tr><tr><td>기능</td><td>출금 건에 한해 [상세] / [출금 취소] 버튼 표시</td></tr></tbody></table><h3 id="거래유형별-테이블-데이터-표시-정책" tabindex="-1">[거래유형별 테이블 데이터 표시 정책] <a class="header-anchor" href="#거래유형별-테이블-데이터-표시-정책" aria-label="Permalink to &quot;[거래유형별 테이블 데이터 표시 정책]&quot;">​</a></h3><h4 id="입금-시" tabindex="-1">입금 시 <a class="header-anchor" href="#입금-시" aria-label="Permalink to &quot;입금 시&quot;">​</a></h4><table tabindex="0"><thead><tr><th>거래유형</th><th>접수번호</th><th>내용</th><th>금액</th><th>잔액</th><th>기능버튼</th></tr></thead><tbody><tr><td>입금</td><td>- (미표시)</td><td>입금 완료</td><td>+금액</td><td>잔액</td><td>없음</td></tr></tbody></table><h4 id="출금-시" tabindex="-1">출금 시 <a class="header-anchor" href="#출금-시" aria-label="Permalink to &quot;출금 시&quot;">​</a></h4><p>출금 신청 후 상태 변화에 따라 내용 컬럼이 업데이트됨</p><table tabindex="0"><thead><tr><th>상태</th><th>거래유형</th><th>내용</th><th>금액</th><th>잔액</th><th>기능버튼</th></tr></thead><tbody><tr><td>출금 신청 직후</td><td>출금</td><td>출금 대기</td><td>-금액</td><td>- (미표시)</td><td>[상세] [출금 취소]</td></tr><tr><td>출금 성공 시</td><td>출금</td><td>출금 완료</td><td>-금액</td><td>- (미표시)</td><td>[상세]</td></tr><tr><td>출금 실패 시</td><td>출금</td><td>출금 실패<br>실패 사유: 정보가 올바르지 않습니다.</td><td>-금액</td><td>- (미표시)</td><td>[상세] [출금]</td></tr></tbody></table><blockquote><p><strong>UI 정책</strong>: 출금 건의 잔액 컬럼은 미표시 (출금 처리는 실시간이 아닌 배치 처리이므로 잔액 확정 전 표시 불필요) <strong>출금 실패 시</strong>: 실패 사유 텍스트를 내용 컬럼 하단에 표시 + [출금] 버튼으로 재출금 신청 가능</p></blockquote><h4 id="사용-시" tabindex="-1">사용 시 <a class="header-anchor" href="#사용-시" aria-label="Permalink to &quot;사용 시&quot;">​</a></h4><table tabindex="0"><thead><tr><th>거래유형</th><th>접수번호</th><th>내용</th><th>금액</th><th>잔액</th><th>기능버튼</th></tr></thead><tbody><tr><td>사용</td><td>sw823533</td><td>제품 접수</td><td>-금액</td><td>잔액</td><td>없음</td></tr></tbody></table><h4 id="사용취소-시" tabindex="-1">사용취소 시 <a class="header-anchor" href="#사용취소-시" aria-label="Permalink to &quot;사용취소 시&quot;">​</a></h4><table tabindex="0"><thead><tr><th>거래유형</th><th>접수번호</th><th>내용</th><th>금액</th><th>잔액</th><th>기능버튼</th></tr></thead><tbody><tr><td>사용취소</td><td>sw823533</td><td>접수 취소</td><td>+금액</td><td>잔액</td><td>없음</td></tr></tbody></table><blockquote><p><strong>사용취소 내용 유형</strong>: 전체취소 환불 / 부분취소 환불</p></blockquote><h4 id="소멸-시" tabindex="-1">소멸 시 <a class="header-anchor" href="#소멸-시" aria-label="Permalink to &quot;소멸 시&quot;">​</a></h4><table tabindex="0"><thead><tr><th>거래유형</th><th>접수번호</th><th>내용</th><th>금액</th><th>잔액</th><th>기능버튼</th></tr></thead><tbody><tr><td>소멸</td><td>- (미표시)</td><td>소멸기한 만료</td><td>-금액</td><td>잔액</td><td>없음</td></tr></tbody></table><h3 id="거래유형별-발생-케이스-정의" tabindex="-1">[거래유형별 발생 케이스 정의] <a class="header-anchor" href="#거래유형별-발생-케이스-정의" aria-label="Permalink to &quot;[거래유형별 발생 케이스 정의]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>유형</th><th>발생 케이스</th><th>내용 텍스트</th></tr></thead><tbody><tr><td><strong>입금</strong></td><td>제품 접수 전 가상계좌 선입금</td><td>입금 완료</td></tr><tr><td><strong>입금</strong></td><td>제품 접수 후 고객이 가상계좌로 입금</td><td>입금 완료</td></tr><tr><td><strong>사용</strong></td><td>제품 접수 시 결제금액 차감</td><td>제품 접수</td></tr><tr><td><strong>사용</strong></td><td>기접수건 자동 차감</td><td>제품 접수</td></tr><tr><td><strong>사용취소</strong></td><td>접수 전체 취소/환불</td><td>전체취소 환불</td></tr><tr><td><strong>사용취소</strong></td><td>부분취소 환불</td><td>부분취소 환불</td></tr><tr><td><strong>출금</strong></td><td>고객 요청에 따른 출금</td><td>출금 대기 → 출금 완료 / 출금 실패</td></tr><tr><td><strong>소멸</strong></td><td>소멸 시효 만료에 따른 예치금 소멸</td><td>소멸기한 만료</td></tr></tbody></table><h3 id="상세-버튼-정책" tabindex="-1">[[상세] 버튼 정책] <a class="header-anchor" href="#상세-버튼-정책" aria-label="Permalink to &quot;[[상세] 버튼 정책]&quot;">​</a></h3><ul><li><strong>노출 조건</strong>: 출금 유형 거래 건에만 [상세] 버튼 노출</li><li><strong>동작</strong>: 마우스 호버 시 툴팁 형태로 출금 상세 정보 표시</li><li><strong>표시 항목</strong>:</li></ul><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>출금자</td><td>예금주명 (예: 정길동)</td></tr><tr><td>출금 은행</td><td>은행명 + 계좌번호 (예: 국민 23444477999998)</td></tr><tr><td>출금 사유</td><td>사용자가 입력한 출금 사유 텍스트</td></tr></tbody></table><h3 id="출금-취소-버튼-정책" tabindex="-1">[[출금 취소] 버튼 정책] <a class="header-anchor" href="#출금-취소-버튼-정책" aria-label="Permalink to &quot;[[출금 취소] 버튼 정책]&quot;">​</a></h3><ul><li><strong>노출 조건</strong>: 출금 상태가 &quot;출금 대기&quot;인 건에만 노출</li><li><strong>노출 제거 조건</strong>: 출금 완료 / 출금 실패로 상태 변경 시 버튼 미노출</li><li><strong>취소 가능 기간</strong>: 출금 신청 후 익일 오후 2시 30분까지</li><li><strong>주말/공휴일 특례</strong>: 금·토·일 신청 건은 월요일 오후 2시 30분에 처리</li><li><strong>취소 완료 시</strong>: 출금가능 잔액으로 즉시 복원</li></ul><hr><h2 id="■-field-rule" tabindex="-1">■ Field Rule <a class="header-anchor" href="#■-field-rule" aria-label="Permalink to &quot;■ Field Rule&quot;">​</a></h2><h3 id="가상계좌-변경" tabindex="-1">[가상계좌 변경] <a class="header-anchor" href="#가상계좌-변경" aria-label="Permalink to &quot;[가상계좌 변경]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>진입 경로</td><td>성원머니 메인 &gt; [가상계좌 변경] 버튼 클릭</td></tr><tr><td>표시 정보</td><td>현재 예금주명 (읽기 전용, 수정 불가)</td></tr><tr><td>입력 항목</td><td>은행 선택</td></tr><tr><td>은행 선택 UI</td><td>버튼형 그리드 (최대 6개 기본 노출)</td></tr><tr><td>이미 등록된 은행</td><td>비활성화 처리 (선택 불가)</td></tr><tr><td>버튼 활성화 조건</td><td>현재 등록된 은행과 다른 은행 선택 시 [변경하기] 버튼 활성화</td></tr><tr><td>변경 제한 안내</td><td>&quot;가상계좌 입금 은행을 변경하신 경우, 변경일로부터 한 달간은 재변경이 어려워요&quot;</td></tr><tr><td>변경 성공 처리</td><td>다이얼로그 닫힘 + 성원머니 페이지 새로고침</td></tr><tr><td>변경 실패 처리</td><td>실패 안내 메시지 표시</td></tr></tbody></table><h4 id="가상계좌-변경-시-은행-목록-기본-노출" tabindex="-1">가상계좌 변경 시 은행 목록 (기본 노출) <a class="header-anchor" href="#가상계좌-변경-시-은행-목록-기본-노출" aria-label="Permalink to &quot;가상계좌 변경 시 은행 목록 (기본 노출)&quot;">​</a></h4><ul><li>국민은행, 우리은행, 신한은행, IBK기업은행, NH농협은행, 수협은행, 하나은행</li><li><strong>비활성화</strong>: 현재 등록된 은행은 선택 불가 상태로 표시</li></ul><hr><h3 id="가상계좌-변경내역-조회" tabindex="-1">[가상계좌 변경내역 조회] <a class="header-anchor" href="#가상계좌-변경내역-조회" aria-label="Permalink to &quot;[가상계좌 변경내역 조회]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>진입 경로</td><td>성원머니 메인 &gt; [변경내역 발급 확인서] 버튼 클릭 (또는 가상계좌 변경내역 다이얼로그)</td></tr><tr><td>테이블 컬럼</td><td>변경일 / 기존은행 / 변경은행</td></tr><tr><td>표시 형식</td><td>변경일: YYYY-MM-DD, 은행명: 약칭 표시 (예: 우리, 하나)</td></tr><tr><td>페이지네이션</td><td>페이지 이동 버튼 제공</td></tr><tr><td>데이터 없을 때</td><td>빈 테이블 표시 또는 안내 문구 표시</td></tr></tbody></table><hr><h3 id="가상계좌-발급-확인서" tabindex="-1">[가상계좌 발급 확인서] <a class="header-anchor" href="#가상계좌-발급-확인서" aria-label="Permalink to &quot;[가상계좌 발급 확인서]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>진입 경로</td><td>가상계좌 변경내역 다이얼로그 또는 별도 버튼 클릭</td></tr><tr><td>문서 형태</td><td>팝업 (새 창)</td></tr><tr><td>표시 항목</td><td>회원 이메일 / 은행명 / 가상계좌번호 / 이용 기관명</td></tr><tr><td>안내 문구</td><td>&quot;상기 발급된 가상계좌는 현재 ㈜성원애드피아의 입금계좌에 종속되어 발급되었음을 확인합니다&quot;</td></tr><tr><td>발급 일자</td><td>확인서 내 날짜 표기 (예: 2025년 09월 16일)</td></tr><tr><td>발급 기관 정보</td><td>사업자등록번호, 상호, 대표, 주소 표기</td></tr></tbody></table><hr><h3 id="환불계좌-변경" tabindex="-1">[환불계좌 변경] <a class="header-anchor" href="#환불계좌-변경" aria-label="Permalink to &quot;[환불계좌 변경]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>진입 경로</td><td>성원머니 메인 &gt; [환불계좌 변경] 버튼 클릭</td></tr><tr><td>표시 정보</td><td>현재 예금주명 (읽기 전용, 수정 불가)</td></tr><tr><td>안내 문구</td><td>&quot;위 예금주 이름이 등록된 이름과 일치하는 계좌만 인증이 가능해요&quot;</td></tr><tr><td>입력 항목</td><td>은행명 선택 + 계좌번호 입력</td></tr><tr><td>버튼 활성화 조건</td><td>은행 선택 + 계좌번호 입력 시 [인증] 버튼 활성화</td></tr><tr><td>개인정보 안내</td><td>&quot;입력하신 정보로 환불 계좌가 변경되며, 기존 동의하신 기간 동안 보관됩니다&quot;</td></tr><tr><td>인증 방식</td><td>[인증] 버튼 클릭 → 계좌인증 API 호출</td></tr><tr><td>인증 성공</td><td>[변경하기] 버튼 활성화 → 클릭 시 환불계좌 변경 완료</td></tr><tr><td>인증 실패</td><td>&quot;계좌 인증에 실패했어요, 입력하신 계좌번호를 확인해주세요&quot; 인라인 메시지 표시</td></tr><tr><td>변경 완료</td><td>다이얼로그 닫힘 + 성원머니 페이지 새로고침</td></tr><tr><td>변경 이력 관리</td><td>변경 이력 저장 없음</td></tr></tbody></table><h4 id="환불계좌-변경-시-은행-목록-전체-표시" tabindex="-1">환불계좌 변경 시 은행 목록 (전체 표시) <a class="header-anchor" href="#환불계좌-변경-시-은행-목록-전체-표시" aria-label="Permalink to &quot;환불계좌 변경 시 은행 목록 (전체 표시)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>행</th><th>은행 목록</th></tr></thead><tbody><tr><td>1</td><td>국민은행, 신한은행, 우리은행</td></tr><tr><td>2</td><td>하나은행, 농협은행, 기업은행</td></tr><tr><td>3</td><td>카카오뱅크, 토스뱅크, 케이뱅크</td></tr><tr><td>4</td><td>SC제일은행, 한국씨티은행, 산업은행</td></tr><tr><td>5</td><td>대구은행, 부산은행, 경남은행</td></tr><tr><td>6</td><td>광주은행, 전북은행, 제주은행</td></tr><tr><td>7</td><td>새마을금고, 신협, 웰컴저축은행</td></tr><tr><td>8</td><td>상호저축은행, NH저축은행, 산림조합</td></tr><tr><td>9</td><td>수협은행, 우체국, 미래에셋증권</td></tr><tr><td>10</td><td>NH투자증권, 유안타증권</td></tr></tbody></table><blockquote><p><strong>UI 정책</strong>: 환불계좌 변경은 전체 은행 목록을 한 번에 표시 (더보기 없음)</p></blockquote><hr><h3 id="출금-신청" tabindex="-1">[출금 신청] <a class="header-anchor" href="#출금-신청" aria-label="Permalink to &quot;[출금 신청]&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>진입 경로</td><td>성원머니 메인 &gt; [출금] 버튼 클릭</td></tr><tr><td>버튼 활성화 조건</td><td>성원머니 출금가능 잔액 &gt; 0원일 경우 [출금] 버튼 활성화</td></tr><tr><td>환불계좌 미등록 시</td><td>&quot;등록된 환불계좌가 없어요&quot; 안내 다이얼로그 표시 → [환불계좌 등록하기] 버튼 제공</td></tr><tr><td>환불계좌 등록 시</td><td>출금 신청 화면으로 진행</td></tr><tr><td>출금 한도</td><td>1회 한도 없음 / 1일 한도 없음 (상한선 무제한)</td></tr></tbody></table><h4 id="출금-가능-잔액-계산" tabindex="-1">출금 가능 잔액 계산 <a class="header-anchor" href="#출금-가능-잔액-계산" aria-label="Permalink to &quot;출금 가능 잔액 계산&quot;">​</a></h4><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>계산 방식</td><td>보유 잔액 - 출금대기 금액 = 출금 가능 잔액</td></tr><tr><td>예시</td><td>보유 150,000원 / 출금대기 20,000원 → 출금가능 130,000원</td></tr><tr><td>초과 입력 시</td><td>입력 금액이 출금가능 금액 초과 시 → 출금가능 금액으로 자동 입력 처리</td></tr></tbody></table><h4 id="출금-금액-빠른-선택" tabindex="-1">출금 금액 빠른 선택 <a class="header-anchor" href="#출금-금액-빠른-선택" aria-label="Permalink to &quot;출금 금액 빠른 선택&quot;">​</a></h4><table tabindex="0"><thead><tr><th>버튼</th><th>기능</th></tr></thead><tbody><tr><td>전액</td><td>출금가능 잔액 전액 자동 입력</td></tr><tr><td>+100만</td><td>현재 입력 금액에 1,000,000원 추가</td></tr><tr><td>+10만</td><td>현재 입력 금액에 100,000원 추가</td></tr><tr><td>+5만</td><td>현재 입력 금액에 50,000원 추가</td></tr><tr><td>+1만</td><td>현재 입력 금액에 10,000원 추가</td></tr></tbody></table><h4 id="출금-사유" tabindex="-1">출금 사유 <a class="header-anchor" href="#출금-사유" aria-label="Permalink to &quot;출금 사유&quot;">​</a></h4><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>선택지</td><td>회계/정산 / 잔액 정리 / 직접 입력</td></tr><tr><td>직접 입력 선택 시</td><td>사유 입력 Textarea 표시 (최대 50자)</td></tr><tr><td>사유 용도</td><td>내부 확인 및 정산 참고용으로만 사용 (외부 공개 없음), [상세] 버튼 호버 시 출금 사유 표시</td></tr></tbody></table><hr><h2 id="■-화면-결과" tabindex="-1">■ 화면 결과 <a class="header-anchor" href="#■-화면-결과" aria-label="Permalink to &quot;■ 화면 결과&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시나리오</th><th>결과</th></tr></thead><tbody><tr><td>가상계좌 변경 성공</td><td>다이얼로그 닫힘 + 성원머니 페이지 새로고침</td></tr><tr><td>가상계좌 변경 실패</td><td>실패 안내 다이얼로그 표시 (고객센터 1599-5555 안내)</td></tr><tr><td>환불계좌 인증 성공</td><td>[변경하기] 버튼 활성화 → 변경 완료 후 다이얼로그 닫힘 + 페이지 새로고침</td></tr><tr><td>환불계좌 인증 실패</td><td>인증 실패 메시지 표시 (계좌번호 재확인 요청)</td></tr><tr><td>출금 신청 완료</td><td>거래내역 테이블에 &quot;출금 대기&quot; 행 즉시 추가</td></tr><tr><td>출금 처리 완료</td><td>&quot;출금 대기&quot; → &quot;출금 완료&quot;로 내용 텍스트 업데이트</td></tr><tr><td>출금 실패</td><td>&quot;출금 실패&quot; + 실패 사유 표시 + [출금] 재신청 버튼 노출</td></tr><tr><td>출금 취소 완료</td><td>출금가능 잔액으로 즉시 복원</td></tr></tbody></table><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><table tabindex="0"><thead><tr><th>상황</th><th>처리</th></tr></thead><tbody><tr><td>가상계좌 발급 실패</td><td>실패 다이얼로그 → 고객센터 문의 안내 (1599-5555) → [닫기]</td></tr><tr><td>계좌 인증 실패</td><td>&quot;계좌 인증에 실패했어요, 입력하신 계좌번호를 확인해주세요&quot; 인라인 메시지 표시</td></tr><tr><td>환불계좌 미등록 상태로 출금 시도</td><td>환불계좌 미등록 안내 다이얼로그 표시</td></tr><tr><td>출금 가능 잔액 0원</td><td>[출금] 버튼 비활성화</td></tr><tr><td>출금 신청 금액 &gt; 출금가능 금액</td><td>출금가능 금액으로 자동 보정 입력</td></tr><tr><td>출금 실패</td><td>거래내역에 실패 사유 텍스트 표시 + [출금] 재신청 버튼 노출</td></tr><tr><td>네트워크 오류</td><td>에러 메시지 표시 및 재시도 유도</td></tr></tbody></table><hr><h2 id="■-출금-취소-정책" tabindex="-1">■ 출금 취소 정책 <a class="header-anchor" href="#■-출금-취소-정책" aria-label="Permalink to &quot;■ 출금 취소 정책&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>취소 가능 기간</td><td>출금 신청 후 익일 오후 2시 30분까지 취소 가능</td></tr><tr><td>주말/공휴일 특례</td><td>금·토·일 신청 건은 월요일 오후 2시 30분에 처리</td></tr><tr><td>취소 후 잔액 복원</td><td>취소 즉시 출금가능 잔액으로 복원</td></tr><tr><td>[출금 취소] 버튼 노출</td><td>거래유형 = 출금 + 내용 = &quot;출금 대기&quot; 상태인 행에만 노출</td></tr><tr><td>[출금 취소] 버튼 제거</td><td>출금 완료 또는 출금 실패로 상태 변경 시 버튼 미노출</td></tr></tbody></table><hr><h2 id="■-현업-확인-필요사항" tabindex="-1">■ 현업 확인 필요사항 <a class="header-anchor" href="#■-현업-확인-필요사항" aria-label="Permalink to &quot;■ 현업 확인 필요사항&quot;">​</a></h2><h3 id="q1-해외-금융기관-추가-여부" tabindex="-1">Q1. 해외 금융기관 추가 여부 <a class="header-anchor" href="#q1-해외-금융기관-추가-여부" aria-label="Permalink to &quot;Q1. 해외 금융기관 추가 여부&quot;">​</a></h3><ul><li><strong>현재 상태</strong>: 현업 확인 필요</li><li><strong>확인 필요 사항</strong>: <ul><li>현재 환불계좌 변경 은행 목록은 국내 금융기관만 지원</li><li>해외 금융기관(외국계 은행, 해외 계좌 등) 추가 지원 여부 결정 필요</li><li>추가 시: 지원 국가 범위, 은행 목록, UI 노출 방식 (별도 탭 또는 기존 목록 통합) 정의 필요</li></ul></li></ul><h3 id="q2-계좌인증-api-업체-계약-확인" tabindex="-1">Q2. 계좌인증 API 업체 계약 확인 <a class="header-anchor" href="#q2-계좌인증-api-업체-계약-확인" aria-label="Permalink to &quot;Q2. 계좌인증 API 업체 계약 확인&quot;">​</a></h3><ul><li><strong>현재 상태</strong>: 현업 확인 필요</li><li><strong>확인 필요 사항</strong>: <ul><li>환불계좌 등록·변경 시 사용되는 계좌인증 API 업체 미확정</li><li>계약 완료 후 인증 실패 사유 코드 및 메시지 정의 필요</li><li>업체별 지원 은행 범위가 다를 수 있으므로, 계약 후 지원 은행 목록 재검토 필요</li></ul></li></ul><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><table tabindex="0"><thead><tr><th>화면명</th><th>필요 사유</th></tr></thead><tbody><tr><td>출금 취소 확인 다이얼로그</td><td>[출금 취소] 클릭 시 재확인 다이얼로그 미제공</td></tr></tbody></table>',79)])])}const q=d(h,[["render",o]]);export{c as __pageData,q as default};
